exercises.solution_code:
#include <iostream>

class A {
public:
    int m_value{};
    A(int value) : m_value{ value } {}
};

class B : virtual public A {
public:
    B(int value) : A{ value } {}

    void greet() const {
        std::cout << "B greet: hello " << m_value << '\n';
    }
};

class C : virtual public A {
public:
    C(int value) : A{ value } {}

    void greet() const {
        std::cout << "C greet: hello " << m_value << '\n';
    }
};

class D : public B, public C {
public:
    D(int value) : A{ value }, B{ value }, C{ value } {}
};

int main() {
    int value{};
    std::cin >> value;

    D d{ value };
    std::cout << "value: " << d.m_value << '\n';
    d.B::greet();
    d.C::greet();

    return 0;
}

